case "${1:-}" in
    --help|-h)
        CLEANUP_QUIET=1
        if command -v less &> /dev/null; then
            show_full_help | less -R
        elif command -v more &> /dev/null; then
            show_full_help | more
        else
            show_full_help
        fi
        exit 0
        ;;
    --force-cleanup)
        force_cleanup
        exit 0
        ;;
    --version|-v)
        CLEANUP_QUIET=1
        echo "$SCRIPT_NAME versi $SCRIPT_VERSION"
        exit 0
        ;;
    "")
        main
        ;;
    *)
        log_error "Opsi salah"; echo "Gunakan --help"; exit 1
        ;;
esac

